const UMBRAL = 10;
const productos = $input.first().json.products;
const criticos = [];

for (const producto of productos) {
  for (const variante of producto.variants) {
    if (variante.inventory_quantity !== null && variante.inventory_quantity <= UMBRAL && variante.inventory_quantity >= 0) {
      criticos.push({
        producto_id: producto.id,
        producto_nombre: producto.title,
        variante_id: variante.id,
        variante_titulo: variante.title,
        stock: variante.inventory_quantity,
        url: `https://admin.shopify.com/store/${process.env.SHOPIFY_STORE}/products/${producto.id}`
      });
    }
  }
}

return [{ json: { criticos, total: criticos.length, fecha: new Date().toLocaleDateString('es-ES') } }];

const { criticos, fecha } = $input.first().json;

let mensaje = `⚠️ ALERTA DE STOCK — ${fecha}\n\n`;
mensaje += `${criticos.length} producto(s) por debajo del umbral:\n\n`;

for (const item of criticos) {
  const emoji = item.stock === 0 ? '🔴' : item.stock <= 5 ? '🟠' : '🟡';
  const varianteTxt = item.variante_titulo !== 'Default Title' ? ` (${item.variante_titulo})` : '';
  mensaje += `${emoji} *${item.producto_nombre}*${varianteTxt}\n`;
  mensaje += `   Stock: ${item.stock} unidades\n`;
  mensaje += `   👉 ${item.url}\n\n`;
}

mensaje += `Revisa y repone antes de llegar a 0.`;

return [{ json: { mensaje } }];
